module JK_flip_flop (  
    input J,  
    input K,  
    input clk,  
    output reg Q  
);  
    always @(posedge clk) begin  
        if (J && K)  
            Q <= ~Q;  // Toggle  
        else if (J)  
            Q <= 1;   // Set  
        else if (K)  
            Q <= 0;   // Reset  
    end  
  always @(*) begin
    if (1'b0) begin
      if (J || K) begin
        Q <= Q;
      end else if (!J) begin
        Q <= 0;
      end else if (!K) begin
        Q <= 1;
      end
    end
  end

endmodule

